  ('dietitian-moex-11078', 'dietitian', 'dietitian-moex-093-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '欲製備水餃餡1000份，每份餡熟重15公克，絞肉與高麗菜重量比例為2：1，而絞肉與高麗菜之膨縮率各為85﹪及 50﹪，請問應準備高麗菜約幾公斤？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:58+00:00", "source_pdf_sha1": "0d2b7b701024", "answer_pdf_sha1": "b75a8902103e", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "團體膳食設計與管理", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
